const body = $input.first().json.body || {};
const { projectId, text, topK, filters } = body;

if (!projectId || typeof projectId !== 'string') throw new Error('projectId required');
if (!text || typeof text !== 'string') throw new Error('text required');

const must = [{ key: 'metadata.projectId', match: { value: projectId } }];
if (filters && typeof filters === 'object') {
  if (filters.source) must.push({ key: 'metadata.source', match: { value: String(filters.source) } });
  if (filters.jurisdiction) must.push({ key: 'metadata.jurisdiction', match: { value: String(filters.jurisdiction) } });
  if (filters.regulationId) must.push({ key: 'metadata.regulationId', match: { value: String(filters.regulationId) } });
}

return [{
  json: {
    projectId,
    text,
    topK: Number.isFinite(topK) && topK > 0 ? Math.min(topK, 50) : 8,
    filter: { must },
  },
}];

const items = $input.all() || [];
const chunks = items.map((it, idx) => {
  const doc = it.json.document || it.json;
  const metadata = (doc && doc.metadata) || it.json.metadata || {};
  const text = (doc && (doc.pageContent || doc.content)) || it.json.pageContent || it.json.content || it.json.text || '';
  const score = typeof it.json.score === 'number' ? it.json.score : (typeof doc?.score === 'number' ? doc.score : 0);
  const documentId = metadata.documentId || '';
  const chunkId = metadata.chunkId || (documentId ? `${documentId}-${idx}` : `chunk-${idx}`);
  return { documentId, chunkId, text, score, metadata };
});
return [{ json: { chunks } }];
